"Encounter: Office Visit" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource, fhirpath_text(r.resource, 'status') AS status, struct_pack(target := r.resourceType || '/' || fhirpath_text(r.resource, 'id'), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := '[Encounter: "Office Visit"]', trace := CAST([] AS VARCHAR[])) AS _audit_item FROM resources r WHERE r.resourceType = 'Encounter' AND EXISTS (SELECT 1 FROM (SELECT unnest(flatten(COALESCE(list_transform(COALESCE(from_json(json_extract(r.resource::JSON, '$.type'), '["JSON"]'), CAST([] AS JSON[])), _cc -> COALESCE(from_json(json_extract(_cc, '$.coding'), '["JSON"]'), CAST([] AS JSON[]))), CAST([] AS JSON[][])))) AS _c) _inv INNER JOIN _vs_1 ON _vs_1._vs_code = json_extract_string(_c, '$.code') AND (_vs_1._vs_system = '' OR _vs_1._vs_system = json_extract_string(_c, '$.system')))
),
