(struct_pack(target := 'ServiceRequest', attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'absent', threshold := 'ServiceRequest: Hospice Care Ambulatory', trace := CAST([] AS VARCHAR[]))) END), _ev -> struct_pack(target := _ev.target, attribute := _ev.attribute, value := _ev.value, operator := _ev.operator, threshold := _ev.threshold, trace := list_append(COALESCE(_ev.trace, CAST([] AS VARCHAR[])), 'Hospice.Has Hospice Services'))))) AS _audit_result FROM _patients AS p LEFT JOIN "Encounter: Encounter Inpatient" ON "Encounter: Encounter Inpatient".patient_id = p.patient_id LEFT JOIN "Encounter: Hospice Encounter" ON "Encounter: Hospice Encounter".patient_id = p.patient_id LEFT JOIN "Observation: Hospice care [Minimum Data Set]" ON "Observation: Hospice care [Minimum Data Set]".patient_id = p.patient_id LEFT JOIN "Procedure: Hospice Care Ambulatory" ON "Procedure: Hospice Care Ambulatory".patient_id = p.patient_id LEFT JOIN "ServiceRequest: Hospice Care Ambulatory" ON "ServiceRequest: Hospice Care Ambulatory".patient_id = p.patient_id
