MP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(PalliativeDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Palliative Care Encounter" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS PalliativeEncounter WHERE PalliativeEncounter.patient_id = p.patient_id AND CAST(intervalStart(fhirpath_text(PalliativeEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(PalliativeEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Palliative Care Intervention" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS PalliativeIntervention WHERE PalliativeIntervention.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"PalliativeCare.Has Palliative Care in the Measurement Period" AS (
SELECT p.patient_id, struct_pack(result := (audit_leaf(EXISTS (SELECT 1 FROM "__pre_PalliativeCare_Has_Palliative_Care_in_the_Measurement_Period" AS __pre WHERE __pre.patient_id = p.patient_id))).result, evidence := list_concat(COALESCE((audit_leaf(EXISTS (SELECT 1 FROM "__pre_PalliativeCare_Has_Palliative_Care_in_the_Measurement_Period" AS __pre WHERE __pre.patient_id = p.patient_id))).evidence, []), list_transform(list_concat(CASE WHEN "Encounter: Palliative Care Encounter"._audit_item IS NOT NULL THEN list_value("Encounter: Palliative Care Encounter"._audit_item) ELSE list_value(struct_pack(target := 'Encounter', attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'absent', threshold := 'Encounter: Palliative Care Encounter', trace := CAST([] AS VARCHAR[]))) END, CASE WHEN "Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)"._audit_item IS NOT NULL THEN list_value("Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)"._audit_item) ELSE list_value(struct_pack(target := 'Observation', attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'absent', threshold := 'Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)', trace := CAST([] AS VARCHAR[]))) END, CASE WHEN "Procedure: Palliative Care Intervention"._audit_item IS NOT NULL THEN list_value("Procedure: Palliative Care Intervention"._audit_item) ELSE list_value(struct_pack(target := 'Procedure', attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'absent', threshold := 'Procedure: Palliative Care Intervention', trace := CAST([] AS VARCHAR[]))) END), _ev -> struct_pack(target := _ev.target, attribute := _ev.attribute, value := _ev.value, operator := _ev.operator, threshold := _ev.threshold, trace := list_append(COALESCE(_ev.trace, CAST([] AS VARCHAR[])), 'PalliativeCare.Has Palliative Care in the Measurement Period'))))) AS _audit_result FROM _patients AS p LEFT JOIN "Encounter: Palliative Care Encounter" ON "Encounter: Palliative Care Encounter".patient_id = p.patient_id LEFT JOIN "Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)" ON "Observation: Functional Assessment of Chronic Illness Therapy - Palliative Care Questionnaire (FACIT-Pal)".patient_id = p.patient_id LEFT JOIN "Procedure: Palliative Care Intervention" ON "Procedure: Palliative Care Intervention".patient_id = p.patient_id
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> to_json(struct_pack(codes := jsonConcat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed')), display := fhirpath_text(_lt_E, 'text')))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource, _inner._audit_item AS _audit_item FROM (SELECT patient_id, to_json(struct_pack(code := fhirpath_text(Payer.resource, 'type'), period := fhirpath_text(Payer.resource, 'period'))) AS _resource_data, Payer._audit_item AS _audit_item FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
