),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN (SELECT json_extract_string(e, '$.valueCode') FROM (SELECT unnest(COALESCE(from_json(json_extract((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)::JSON, '$.extension'), '["JSON"]'), CAST([] AS JSON[]))) AS e) _ext_t WHERE json_extract_string(e, '$.url') = 'http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex' LIMIT 1) = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN (SELECT json_extract_string(e, '$.valueCode') FROM (SELECT unnest(COALESCE(from_json(json_extract((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)::JSON, '$.extension'), '["JSON"]'), CAST([] AS JSON[]))) AS e) _ext_t WHERE json_extract_string(e, '$.url') = 'http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex' LIMIT 1) = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Absence of Cervix" AS (
(SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Hysterectomy with No Residual Cervix" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS NoCervixProcedure WHERE CAST(intervalEnd(CASE WHEN fhirpath_text(NoCervixProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(NoCervixProcedure.resource, 'performed')), '{') THEN fhirpath_text(NoCervixProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(NoCervixProcedure.resource, 'performed'), fhirpath_text(NoCervixProcedure.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) UNION (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Congenital or Acquired Absence of Cervix (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Congenital or Acquired Absence of Cervix (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS NoCervixDiagnosis WHERE CAST(intervalStart(CASE WHEN fhirpath_text(NoCervixDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(NoCervixDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NoCervixDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NoCervixDiagnosis.resource, 'recordedDate')), fhirpath_text(NoCervixDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(NoCervixDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NoCervixDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NoCervixDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN EXISTS (SELECT 1 FROM (SELECT unnest(COALESCE(from_json(json_extract(NoCervixDiagnosis.resource::JSON, '$.clinicalStatus.coding'), '["JSON"]'), from_json(json_extract(NoCervixDiagnosis.resource::JSON, '$.clinicalStatus[0].coding'), '["JSON"]'), CAST([] AS JSON[]))) AS c) _fbt WHERE (json_extract_string(c, '$.code') = 'active' OR json_extract_string(c, '$.code') = 'recurrence' OR json_extract_string(c, '$.code') = 'relapse')) THEN intervalFromBounds(COALESCE(fhirpath_text(NoCervixDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NoCervixDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NoCervixDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(NoCervixDiagnosis.resource, 'onsetDateTime'), fhirpath_text(NoCervixDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(NoCervixDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= CAST('2026-12-31T23:59:59.999' AS TIMESTAMP))
),
"Cervical Cytology Within 3 Years" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Observation: Pap Test" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS CervicalCytology WHERE CAST(COALESCE(fhirpath_date(CervicalCytology.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(CervicalCytology.resource, 'effectivePeriod'))) AS DATE) >= CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 2.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(COALESCE(fhirpath_date(CervicalCytology.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(CervicalCytology.resource, 'effectivePeriod'))) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(CervicalCytology.resource, 'value') IS NOT NULL
),
"__pre_Denominator_Exclusions" AS (
