),
"Denominator Exclusions" AS (
SELECT p.patient_id, struct_pack(result := (audit_leaf(EXISTS (SELECT 1 FROM "__pre_Hospice_Has_Hospice_Services" AS sub WHERE sub.patient_id = p.patient_id))).result OR (audit_leaf(EXISTS (SELECT 1 FROM "Absence of Cervix" AS sub WHERE sub.patient_id = p.patient_id))).result OR (audit_leaf(EXISTS (SELECT 1 FROM "__pre_PalliativeCare_Has_Palliative_Care_in_the_Measurement_Period" AS sub WHERE sub.patient_id = p.patient_id))).result, evidence := list_concat(COALESCE( CASE WHEN (audit_leaf(EXISTS (SELECT 1 FROM "__pre_Hospice_Has_Hospice_Services" AS sub WHERE sub.patient_id = p.patient_id))).result THEN COALESCE((audit_leaf(EXISTS (SELECT 1 FROM "__pre_Hospice_Has_Hospice_Services" AS sub WHERE sub.patient_id = p.patient_id))).evidence, []) WHEN (audit_leaf(EXISTS (SELECT 1 FROM "Absence of Cervix" AS sub WHERE sub.patient_id = p.patient_id))).result THEN COALESCE((audit_leaf(EXISTS (SELECT 1 FROM "Absence of Cervix" AS sub WHERE sub.patient_id = p.patient_id))).evidence, []) ELSE COALESCE((audit_leaf(EXISTS (SELECT 1 FROM "__pre_PalliativeCare_Has_Palliative_Care_in_the_Measurement_Period" AS sub WHERE sub.patient_id = p.patient_id))).evidence, []) END, []), list_transform(list_concat(COALESCE((SELECT CASE WHEN count(*) = 0 THEN list_value(struct_pack(target := 'Absence of Cervix', attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'absent', threshold := 'Absence of Cervix', trace := CAST([] AS VARCHAR[]))) ELSE list(struct_pack(target := COALESCE(fhirpath_text(_sub.resource, 'resourceType'), '') || '/' || COALESCE(fhirpath_text(_sub.resource, 'id'), ''), attribute := CAST(NULL AS VARCHAR), value := CAST(NULL AS VARCHAR), operator := 'exists', threshold := 'Absence of Cervix', trace := CAST(['Absence of Cervix'] AS VARCHAR[]))) END FROM "Absence of Cervix" AS _sub WHERE _sub.patient_id = p.patient_id), []), COALESCE((SELECT __bev_0._audit_result.evidence FROM "Hospice.Has Hospice Services" AS __bev_0 WHERE __bev_0.patient_id = p.patient_id), []), COALESCE((SELECT __bev_1._audit_result.evidence FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS __bev_1 WHERE __bev_1.patient_id = p.patient_id), [])), _ev -> struct_pack(target := _ev.target, attribute := _ev.attribute, value := _ev.value, operator := _ev.operator, threshold := _ev.threshold, trace := list_append(COALESCE(_ev.trace, CAST([] AS VARCHAR[])), 'Denominator Exclusions'))))) AS _audit_result FROM _patients AS p
),
"HPV Test Within 5 Years for Women Age 30 and Older" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Observation: HPV Test" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HPVTest WHERE struct_extract(audit_and(audit_comparison(EXTRACT(YEAR FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) THEN 1 ELSE 0 END >= 30, '>=', EXTRACT(YEAR FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = HPVTest.patient_id LIMIT 1)) THEN 1 ELSE 0 END, 30, CAST(NULL AS VARCHAR), CAST(NULL AS VARCHAR)), audit_leaf(CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE) >= CAST(dateSubtractQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 4.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS DATE) AND CAST(COALESCE(fhirpath_date(HPVTest.resource, 'effectiveDateTime'), intervalEnd(fhirpath_text(HPVTest.resource, 'effectivePeriod'))) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE) AND fhirpath_text(HPVTest.resource, 'value') IS NOT NULL)), 'result')
),
"__pre_Numerator" AS (
