SELECT p.patient_id, compact_audit(COALESCE("Initial Population"._audit_result, struct_pack(result := FALSE, evidence := []))) AS "Initial Population", compact_audit(COALESCE("Denominator"._audit_result, struct_pack(result := FALSE, evidence := []))) AS Denominator, compact_audit(COALESCE("Denominator Exclusions"._audit_result, struct_pack(result := FALSE, evidence := []))) AS "Denominator Exclusions", compact_audit(COALESCE("Numerator"._audit_result, struct_pack(result := FALSE, evidence := []))) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
